+  _x_sum += x;
+  _y_sum += y;
+  _xy_sum += x * y;
+  _xx_sum += x * x;
+  _yy_sum += y * y;
+  _weighted_y_sum += y * weight;
+  _weighted_sum += weight;
+  _weighted_yy_sum += y * y * weight;
+}
